  ('promotion-29a002de-moex-00034', 'promotion-29a002de', 'promotion-29a002de-moex-114-3082b5f1', 'sub-promotion-29a002de-04', NULL, 'single_choice', '下列何者不得提起行政訴訟之確認訴訟？', '["公立學校教師經學校解聘後，對該解聘不服", "人民對於違反專屬管轄之行政處分不服", "違建已倒塌，所有權人對該建物拆除處分不服", "政府採購案未得標廠商對決標處分不服"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00035', 'promotion-29a002de', 'promotion-29a002de-moex-114-3082b5f1', 'sub-promotion-29a002de-04', NULL, 'single_choice', '關於行政訴訟第一審裁判之敘述，下列何者正確？', '["法官非參與裁判基礎之辯論者，不得參與裁判", "各種獨立之攻擊或防禦方法，達於可為裁判之程度者，行政法院應為終局判決", "當事人兩造於言詞辯論期日，無正當理由均不到場者，行政法院不得逕為判決", "行政法院對於行政機關依裁量權所為之行政處分，均不得予以撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00036', 'promotion-29a002de', 'promotion-29a002de-moex-114-3082b5f1', 'sub-promotion-29a002de-04', NULL, 'single_choice', '下列何者非國家賠償法所稱之公務員？', '["依據船員法行使處分權之商船船長", "代辦汽車定期檢驗之私人修車廠", "協助公立學校老師進行實驗之學生", "評定學生分數之私立大學教師"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00037', 'promotion-29a002de', 'promotion-29a002de-moex-114-3082b5f1', 'sub-promotion-29a002de-04', NULL, 'single_choice', '關於行政上補償之敘述，下列何者錯誤？', '["對於犯罪被害人補償，非基於特別犧牲", "施打疫苗造成下肢癱瘓，基於特別犧牲法理應予補償", "徵收土地是合法有目的性侵害財產權", "法規准許廢止授益處分時，凡受益人均得請求信賴利益損失補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "123", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00038', 'promotion-29a002de', 'promotion-29a002de-moex-112-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲因重傷害案件經臺灣高等法院判決有罪，該判決經甲上訴最高法院遭
駁回而確定。甲仍不服該確定判決，遂向臺灣高等法院聲請再審，惟仍
遭裁定駁回再審聲請。甲收受駁回再審聲請之裁定後，發現參與該駁回
再審聲請裁定法官，其曾參與自己先前重傷害案件之臺灣高等法院確定
判決，甲遂基於此一理由，向最高法院提起抗告。試問甲之抗告有無理
由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "73b77b54d5a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0508", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00039', 'promotion-29a002de', 'promotion-29a002de-moex-112-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '詐騙集團首腦甲遭警方以涉嫌詐欺為由，通知到場接受詢問，遂委任乙
律師為辯護人，並在徵求乙同意之後，將自己因詐騙獲取的 1千萬元犯
罪所得藏匿在乙律師事務所的密室內，以躲避未來可能的沒收執行。本
案承辦檢察官獲得可靠情資得知此事，遂向法院聲請對第三人乙之搜索
票獲准，前往搜索乙之律師事務所，並搜出甲與乙為辯護工作準備所記
錄的諮詢過程筆記（其中包含甲自述的詐騙集團組織與運作細節紀錄），
以及密室當中的1 千萬元現金，檢察官遂當場扣押該筆記與 1千萬元現
金。試問檢察官之搜索與扣押是否合法？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "73b77b54d5a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0508", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00040', 'promotion-29a002de', 'promotion-29a002de-moex-112-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲某日在一參與人數多達數百人的通訊軟體對話群組當中，傳送有關乙
之不實性愛影像，並在傳送完十分鐘內，確認已有多人讀取該訊息之後，
收回該影像訊息。乙並未參與該群組，但經友人告知有此事後，憤而向
檢察官提告，並檢具友人截圖保留的訊息影像之電磁紀錄檔案作為證
據。檢察官隨後傳喚甲到場說明，甲否認犯罪，且同意由檢察官開啟並
查閱甲之手機內容，但檢察官已經完全無法找到該張有關乙的不實性愛
影像，甲也早已經完全刪除當日傳送訊息之內容。檢察官隨後以乙所提
供友人保留訊息影像的截圖電磁紀錄檔案作為證據之一，將甲起訴。試
問該電磁紀錄檔案得否作為法院判斷之依據？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "73b77b54d5a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0508", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00041', 'promotion-29a002de', 'promotion-29a002de-moex-112-8d1d3a67', 'sub-promotion-29a002de-01', NULL, 'essay', '甲與乙為夫妻，兩人某日在路旁散步時，同時遭酒醉駕車之 A開車撞傷。
A事後欲與甲、乙二人和解，出具和解書表示願意賠償二人各 10萬元，
但甲、乙二人應聲明放棄對 A 提起刑事告訴。甲覺得 A 極有和解之誠
意，遂明白表示不願對 A提起刑事告訴，並簽署和解書與放棄提起刑事
告訴之聲明。乙則是不願原諒 A，遂以自己名義，為甲與自己向檢察官
提起刑事告訴。檢察官受理告訴之後，傳喚甲與A到場訊問，A表示甲
已放棄提起告訴，並無告訴權；甲則是同樣表示已經放棄提起告訴，因
此當場向檢察官表示要撤回乙所提起之有關甲與乙的全部刑事告訴。試
問甲之「放棄告訴聲明」與「撤回告訴」之行為是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "73b77b54d5a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0508", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00042', 'promotion-29a002de', 'promotion-29a002de-moex-112-98c44bb8', 'sub-promotion-29a002de-02', NULL, 'essay', '甲、乙二人於民國（下同）108 年間共同出資進行都市更新建案，並委
任丙公司擔任都更實施者。111 年 5 月間，上開都市更新建案之房屋興
建完成，丙公司因此成為甲、乙二人分得 A、B、C 三房地之登記名義
人。其後甲、乙二人因分屋發生爭執，甲為免丙公司曲意維護乙而恣意
處分甲、乙二人分得之上開房地，遂依法聲請就 A、B 房地為假處分獲
准，並經臺灣臺北地方法院（下稱執行法院）對 A、B 房地為扣押。其
後，甲具狀向執行法院追加 C房地為執行標的，試問執行法院應為如何
之處理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "96fe8a20a6a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與國際私法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL),
  ('promotion-29a002de-moex-00043', 'promotion-29a002de', 'promotion-29a002de-moex-112-98c44bb8', 'sub-promotion-29a002de-02', NULL, 'essay', '甲出生於書香世家，自幼環境優渥，遂養成揮霍之惡習。23 歲時，甲自
祖父獲贈名貴之青瓷花瓶乙只，市價估逾千萬。甲因揮金如土，除上開
青瓷花瓶外已無任何財產。嗣甲債台高築急需資金，將青瓷花瓶以新臺
幣（下同）700 萬元出賣予乙，乙將價金交付甲後，甲遲遲不願交付花
瓶予乙，乙被迫訴請甲交付花瓶獲勝訴判決確定後，對甲聲請強制執行。
翌日，甲之另名債權人丙持載明債權額為600萬之訴訟上和解筆錄，對
甲聲請強制執行。試問執行法院扣押上開青瓷花瓶後，應為如何之處
理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:50+00:00", "source_pdf_sha1": "96fe8a20a6a3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "123", "s": "0515", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "強制執行法與國際私法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "司法行政"}'::jsonb, NULL)
